  },
  "globalDesign": {
    "style": "Medical Diagnostic / Clinical X-ray",
    "tone": "Serious, Professional, Analytical",
    "targetImpression": "Urgency, medical focus, diagnostic clarity, identifying a problem area",
    "fontPolicy": {
      "primary": "N/A",
      "secondary": "N/A",
      "note": "No text elements present in the original image."
    },
    "spacingPolicy": {
      "overall": "Spacious with high negative space",
      "margin": "Subject is centered-left with focus area on the right",
      "elementGap": "N/A"
    },
    "contrastPolicy": {
      "level": "High",
      "note": "Bright blue-white X-ray imagery against a pure black background with a vivid red accent."
    },
    "visualStyle": {
      "type": "Radiographic Photography (X-ray)",
      "mood": "Clinical and cold",
      "note": "Side profile (lateral view) of a human skull and cervical spine."
    },
    "gridAlignment": {
      "horizontal": "Left-to-center for the subject, right-weighted for the highlight",
      "vertical": "Centered",
      "note": "The composition follows the natural anatomy of the head and neck."
    },
    "designRationale": "The high contrast between the black background and the blue X-ray immediately draws attention to the anatomical structure, while the red circle creates a powerful focal point to indicate a specific area of concern or pathology."
  },
  "colorScheme": {
    "main": "#000000",
    "sub": "#A0C4FF",
    "accent": "#FF0000",
    "background": "#000000",
    "usage": {
      "main": "Deep black background to provide maximum contrast for the X-ray",
      "accent": "Bright red circle to highlight the specific area of interest (cervical spine)",
      "background": "Solid black"
    },
    "designNote": "The palette is restricted to medical blue-whites and a single warning color (red) to maintain a professional and urgent medical tone."
  },
  "zones": [
    {
      "name": "Main Visual Zone",
      "position": "0%-100%",
      "purpose": "To display the anatomical subject and the specific point of interest.",
      "background": "#000000",
      "elements": [
        {
          "type": "image",
          "role": "photo",
          "description": "Lateral X-ray view of a human head and neck, showing the skull, jaw, and cervical vertebrae in translucent blue and white tones.",
          "position": {
            "top": "50%",
            "left": "45%"
          },
          "size": "Large",
          "effect": "Glow, transparency, high contrast"
        },
        {
          "type": "shape",
          "role": "badge",
          "description": "A thick, bright red circle highlighting the middle section of the cervical spine.",
          "position": {
            "top": "65%",
            "left": "65%"
          },
          "size": "Medium"
        }
      ]
    }
  ],
  "reproduction": {
    "keyPoints": [
      "Maintain the high-contrast black background to make the X-ray 'pop'.",
      "Ensure the X-ray has a distinct blue/cyan tint rather than pure grayscale.",
      "The red circle must be a pure, saturated red to act as a clear visual indicator.",
      "The profile view of the skull should be sharp and anatomically recognizable."
    ],
    "colorToneNote": "The blue tones should range from deep navy to bright cyan-white to simulate the look of a backlit X-ray film.",
    "layoutNote": "The subject should face left, leaving enough space on the right for the highlight circle and potential future text placement."
  }
}

