{
  "basic": {
    "aspectRatio": "1:1",
    "size": "1080x1080px"
  },
  "globalDesign": {
    "style": "レトロモダン・マンガスタイル",
    "tone": "ドラマチックかつ解決志向",
    "targetImpression": "現状への焦りと、提示された解決策への驚き・期待感",
    "fontPolicy": {
      "primary": "極太の明朝体（縦書き）",
      "secondary": "太めのゴシック体（注釈用）",
      "note": "文字には太い白縁取りと黒のドロップシャドウを適用し、可読性を最大化している"
    },
    "spacingPolicy": {
      "overall": "2コマ構成のタイトなレイアウト",
      "margin": "外周に太い黒枠線",
      "elementGap": "上下のコマを太い黒線で分割"
    },
    "contrastPolicy": {
      "level": "高い",
      "note": "背景のクリーム色に対し、黒の太い主線と鮮やかなアクセントカラーで強いインパクトを生んでいる"
    },
    "visualStyle": {
      "type": "日本のアニメ・マンガ風イラスト",
      "mood": "感情表現が豊かでダイナミック",
      "note": "劇画調のタッチ、集中線的な効果、瞳のハイライトが特徴的"
    },
    "gridAlignment": {
      "horizontal": "中央揃え（人物）、左右振り分け（テキスト）",
      "vertical": "上下2分割",
      "note": "視線が上から下へ、そして中央のキャラクターから左右のテキストへ流れるように配置"
    },
    "designRationale": "マンガのコマ割り形式を採用することで、ストーリー性を感じさせ、ユーザーの自分事化を促進する。劇的な表情の変化で解決策のインパクトを強調している。"
  },
  "colorScheme": {
    "main": "#3A8E98",
    "sub": "#221815",
    "accent": "#F39800",
    "background": "#FDF5E6",
    "usage": {
      "main": "キャラクターの衣服（落ち着いたトーンのティール）",
      "accent": "スマートフォンの筐体（視線を誘導するオレンジ）",
      "background": "全体の背景色（目に優しいクリーム色）"
    },
    "designNote": "全体的に彩度を抑えたノスタルジックな配色に、スマートフォンのオレンジが現代的なアクセントとして機能している"
  },
  "zones": [
    {
      "name": "上部パネル（問題提起）",
      "position": "0%-50%",
      "purpose": "現状の悩みと目標の提示",
      "background": "#FDF5E6",
      "elements": [
        {
          "type": "image",
          "role": "photo",
          "description": "不安そうな表情でスマートフォンを見つめる茶髪の女性のイラスト。汗のマークがあり、困惑している様子。",
          "position": {
            "top": "25%",
            "left": "50%"
          },
          "size": "中サイズ",
          "effect": "太い黒の輪郭線"
        },
        {
          "type": "text",
          "role": "headline",
          "content": "最短{数値}日",
          "position": {
            "top": "25%",
            "left": "15%"
          },
          "size": "特大",
          "font": "極太明朝体",
          "color": "#221815",
          "effect": "白縁取り、黒影、縦書き"
        },
        {
          "type": "text",
          "role": "headline",
          "content": "{成果}まで",
          "position": {
            "top": "25%",
            "left": "85%"
          },
          "size": "特大",
          "font": "極太明朝体",
          "color": "#221815",
          "effect": "白縁取り、黒影、縦書き"
        }
      ]
    },
    {
      "name": "下部パネル（解決策提示）",
      "position": "50%-97%",
      "purpose": "具体的な手段の提示と驚き",
      "background": "#FDF5E6",
      "elements": [
        {
          "type": "image",
          "role": "photo",
          "description": "女性の顔のアップ。目を見開き、瞳の中に星のような輝きがある。驚きと希望に満ちた表情。",
          "position": {
            "top": "75%",
            "left": "50%"
          },
          "size": "大サイズ（クローズアップ）",
          "effect": "劇画調の斜線シャドウ"
        },
        {
          "type": "text",
          "role": "subheadline",
          "content": "忙しい{ターゲット}でも",
          "position": {
            "top": "75%",
            "left": "85%"
          },
          "size": "大",
          "font": "極太明朝体",
          "color": "#221815",
          "effect": "白縁取り、黒影、縦書き"
        },
        {
          "type": "text",
          "role": "body",
          "content": "1日{数値}分 {サービス名}だと",
          "position": {
            "top": "75%",
            "left": "15%"
          },
          "size": "大",
          "font": "極太明朝体",
          "color": "#221815",
          "effect": "白縁取り、黒影、縦書き"
        }
      ]
    },
    {
      "name": "フッター（注釈）",
      "position": "97%-100%",
      "purpose": "免責事項の表示",
      "background": "#FDF5E6",
      "elements": [
        {
          "type": "text",
          "role": "caption",
          "content": "※学習効果には個人差があります。合格を保証するものではありません。※{サービス名}の全講座が対象ではありません。詳細はWebサイトをご確認ください。",
          "position": {
            "top": "98.5%",
            "left": "50%"
          },
          "size": "極小",
          "font": "ゴシック体",
          "color": "#221815",
          "effect": "なし"
        }
      ]
    }
  ],
  "reproduction": {
    "keyPoints": [
      "上下2コマのマンガ構成を維持し、表情のビフォーアフターを明確に描くこと",
      "テキストはすべて縦書きにし、太い白縁取りを付けて背景から浮かび上がらせること",
      "キャラクターの瞳の描き込み（キラキラしたハイライト）を強調し、希望を表現すること"
    ],
    "colorToneNote": "背景は真っ白ではなく、少し古紙のような温かみのあるクリーム色（#FDF5E6）を使用すること",
    "layoutNote": "中央にキャラクターを配置し、その左右の空きスペースに縦書きテキストを配置する左右対称に近いレイアウトを意識すること"
  }
}

